use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract metadata from PDF
sub extract_metadata {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $info = $pdf->info;
    my $author = $info->author // 'Unknown Author';
    my $title = $info->title // 'Unknown Title';
    my $creation_date = $info->creation_date // 'Unknown Creation Date';

    return ($author, $title, $creation_date);
}

# Function to extract text from PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';

    foreach my $page (1 .. $pdf->pages) {
        my $text_page = $pdf->page($page)->textout(0, 0);
        $text .= $text_page;
    }

    return $text;
}

# Main program
my $pdf_file = 'example.pdf';  # Replace with your PDF file path

# Extract metadata
my ($author, $title, $creation_date) = extract_metadata($pdf_file);
print "Author: $author\n";
print "Title: $title\n";
print "Creation Date: $creation_date\n";

# Extract text
my $text = extract_text($pdf_file);
print "Extracted Text:\n$text\n";
